@namespace Lumeo
@implements IAsyncDisposable

@{
    var context = new CarouselContext(
        _contentId,
        Orientation,
        _canScrollPrev && !Disabled,
        _canScrollNext && !Disabled,
        EventCallback.Factory.Create(this, ScrollPrev),
        EventCallback.Factory.Create(this, ScrollNext)
    );
}

<div role="region" aria-roledescription="carousel" class="@CssClass" @onkeydown="HandleKeyDown" @onkeydown:preventDefault="true" @attributes="AdditionalAttributes">
    <CascadingValue Value="context" IsFixed="false">
        @ChildContent
    </CascadingValue>
</div>

@inject ComponentInteropService Interop
@inject ThemeService Theme

@code {
    [Parameter] public CarouselOrientation Orientation { get; set; } = CarouselOrientation.Horizontal;
    [Parameter] public bool Loop { get; set; }
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private int _currentIndex;
    private bool _canScrollPrev;
    private bool _canScrollNext = true;
    private readonly string _contentId = $"carousel-{Guid.NewGuid():N}";

    private string CssClass => $"relative {Class}".Trim();

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;
        try
        {
            var orientationStr = Orientation == CarouselOrientation.Horizontal ? "horizontal" : "vertical";
            await Interop.RegisterCarouselSwipe(
                _contentId,
                orientationStr,
                OnSwipe,
                OnScrollPosition
            );
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
    }

    private async Task OnSwipe(string direction)
    {
        if (direction == "prev")
            await ScrollPrev();
        else if (direction == "next")
            await ScrollNext();
    }

    private Task OnScrollPosition(double scrollPos, double maxScroll, int nearestIndex)
    {
        var prevP = _canScrollPrev;
        var prevN = _canScrollNext;
        _canScrollPrev = scrollPos > 0;
        _canScrollNext = scrollPos < maxScroll - 1;
        // Sync _currentIndex from the scroll position so button navigation
        // (ScrollNext/ScrollPrev) stays accurate after touch-swipe.
        if (nearestIndex >= 0)
            _currentIndex = nearestIndex;
        if (prevP != _canScrollPrev || prevN != _canScrollNext)
            StateHasChanged();
        return Task.CompletedTask;
    }

    private async Task ScrollPrev()
    {
        if (Disabled) return;
        if (!_canScrollPrev && !Loop) return;

        if (_canScrollPrev)
        {
            _currentIndex--;
        }
        else if (Loop)
        {
            _currentIndex = -1;
        }

        await Interop.CarouselScrollTo(_contentId, _currentIndex < 0 ? int.MaxValue : _currentIndex);
        StateHasChanged();
    }

    private async Task ScrollNext()
    {
        if (Disabled) return;
        if (!_canScrollNext && !Loop) return;

        if (_canScrollNext)
        {
            _currentIndex++;
        }
        else if (Loop)
        {
            _currentIndex = 0;
        }

        await Interop.CarouselScrollTo(_contentId, _currentIndex);
        StateHasChanged();
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (Disabled) return;
        if (Orientation == CarouselOrientation.Horizontal)
        {
            var isRtl = Theme.CurrentDirection == LayoutDirection.Rtl;
            var (back, forward) = isRtl ? ("ArrowRight", "ArrowLeft") : ("ArrowLeft", "ArrowRight");
            if (e.Key == back) await ScrollPrev();
            else if (e.Key == forward) await ScrollNext();
        }
        else
        {
            if (e.Key == "ArrowUp") await ScrollPrev();
            else if (e.Key == "ArrowDown") await ScrollNext();
        }
    }

    public async ValueTask DisposeAsync()
    {
        try
        {
            await Interop.UnregisterCarouselSwipe(_contentId);
        }
        catch (JSDisconnectedException) { }
    }

    public enum CarouselOrientation { Horizontal, Vertical }

    public record CarouselContext(
        string ContentId,
        CarouselOrientation Orientation,
        bool CanScrollPrev,
        bool CanScrollNext,
        EventCallback ScrollPrev,
        EventCallback ScrollNext
    );
}

@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes">
    @if (Context.Orientation == Carousel.CarouselOrientation.Horizontal)
    {
        <div id="@Context.ContentId"
             class="flex -ms-4"
             style="overflow-x: auto; scroll-snap-type: x mandatory; scroll-behavior: smooth; -webkit-overflow-scrolling: touch; scrollbar-width: none;">
            @ChildContent
        </div>
    }
    else
    {
        <div id="@Context.ContentId"
             class="flex flex-col -mt-4"
             style="overflow-y: auto; scroll-snap-type: y mandatory; scroll-behavior: smooth; -webkit-overflow-scrolling: touch; scrollbar-width: none;">
            @ChildContent
        </div>
    }
</div>

@code {
    [CascadingParameter] public Carousel.CarouselContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"overflow-hidden {Class}".Trim();
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@{
    var isHorizontal = Context.Orientation == Carousel.CarouselOrientation.Horizontal;
    var cssClass = isHorizontal
        ? $"min-w-0 shrink-0 grow-0 basis-full ps-4 {Class}".Trim()
        : $"min-w-0 shrink-0 grow-0 basis-full pt-4 {Class}".Trim();
}

<div role="group" aria-roledescription="slide" aria-label="@SlideLabel" class="@cssClass" style="scroll-snap-align: start;" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [CascadingParameter] public Carousel.CarouselContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public int? Index { get; set; }
    [Parameter] public int? Total { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string? SlideLabel => Index.HasValue && Total.HasValue
        ? L["Carousel.SlideXofY", Index.Value, Total.Value]
        : null;
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@{
    var isHorizontal = Context.Orientation == Carousel.CarouselOrientation.Horizontal;
    var positionClass = isHorizontal
        ? "-end-12 top-1/2 -translate-y-1/2"
        : "left-1/2 -translate-x-1/2 -bottom-12";
}

<button class="@($"absolute h-8 w-8 rounded-full border bg-background shadow-sm inline-flex items-center justify-center hover:bg-accent hover:text-accent-foreground disabled:pointer-events-none disabled:opacity-50 {positionClass} {Class}".Trim())"
        disabled="@(!Context.CanScrollNext)"
        aria-label="@L["Carousel.NextSlide"]"
        @onclick="() => Context.ScrollNext.InvokeAsync()"
        @attributes="AdditionalAttributes">
    @if (isHorizontal)
    {
        <Blazicon Svg="Lucide.ChevronRight" class="h-4 w-4 [dir=rtl]:rotate-180" />
    }
    else
    {
        <Blazicon Svg="Lucide.ChevronDown" class="h-4 w-4" />
    }
    <span class="sr-only">@L["Carousel.NextSlide"]</span>
</button>

@code {
    [CascadingParameter] public Carousel.CarouselContext Context { get; set; } = default!;
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }
}

