<button class="@($"absolute h-8 w-8 rounded-full border bg-background shadow-sm inline-flex items-center justify-center hover:bg-accent hover:text-accent-foreground disabled:pointer-events-none disabled:opacity-50 {positionClass} {Class}".Trim())"
